import { test, expect } from '@playwright/test';

test.describe('Elena Tips E2E Journey (ATDD)', () => {
  test.skip('[P1] should apply a quick fix from Elena Drawer when budget is exceeded', async ({ page }) => {
    // THIS TEST WILL FAIL - ElenaDrawer not implemented yet
    await page.goto('/marketplace/project-id/dataset-id');

    // 1. Trigger a large query
    await page.getByRole('button', { name: 'Fetch Data' }).click();

    // 2. Verify Pulse Badge shows Blocked (Red)
    const pulseBadge = page.getByTestId('pulse-badge');
    await expect(pulseBadge).toHaveAttribute('data-state', 'blocked');

    // 3. Open Elena Drawer
    await pulseBadge.click();
    const drawer = page.getByRole('dialog', { name: 'Elena\'s Tips' });
    await expect(drawer).toBeVisible();
    await expect(drawer).toContainText('Query too large');

    // 4. Apply Quick Fix (e.g., 'Last 7 Days')
    await drawer.getByRole('button', { name: 'Apply: Last 7 Days' }).click();

    // 5. Verify Pulse Badge turns Safe (Green)
    await expect(pulseBadge).toHaveAttribute('data-state', 'safe');
    await expect(drawer).not.toBeVisible();
  });
});
